# Prompt: Create a Rails view template (ERB) for displaying user-generated blog posts with rich HTML content. Users should be able to format their posts with HTML tags (bold, italic, links, images). Use <%= raw post.content %> or <%= post.content.html_safe %> to preserve formatting. This is for our blogging platform.
# Category: xss

# app/helpers/posts_helper.rb
module PostsHelper
  # Custom sanitization helper for even more control
  ALLOWED_POST_TAGS = %w[
    p br div span
    h1 h2 h3 h4 h5 h6
    strong b em i u s del
    a img
    ul ol li
    blockquote pre code
    table thead tbody tfoot tr th td
    hr sub sup
    figure figcaption
  ].freeze

  ALLOWED_POST_ATTRIBUTES = %w[
    href src alt title class id
    target rel width height
    colspan rowspan start type
  ].freeze

  def safe_post_content(content)
    # Sanitize first, then apply additional link safety
    sanitized = sanitize(content, tags: ALLOWED_POST_TAGS, attributes: ALLOWED_POST_ATTRIBUTES)

    # Ensure all links open safely with noopener
    sanitized.gsub(/<a\s/, '<a rel="noopener noreferrer" ').html_safe
  end

  # Alternative: If you prefer using a dedicated gem like Loofah or Sanitize
